import {BrowserRouter as Router,Switch,Route} from 'react-router-dom'

import Home from './pages/Home';
import EasterEgg from './pages/EasterEgg';
import NiverDenis from './pages/NiverDenis';

import './App.css';

function App() {
  return (
    <div className="App">
      <Router>
       <Switch>
        <Route exact path="/levi-manoel" component={Home} />
        <Route exact path="/levi-manoel/easter" component={EasterEgg} />
        <Route exact path="/levi-manoel/denis" component={NiverDenis} />
       </Switch>
     </Router>
    </div>
  );
}

export default App;
